#include <iostream>
using namespace std;

int main() {
    // Implicit conversion
    int a = 10;
    float b = a;  // int to float (automatic)
    cout << "Implicit: " << b << endl;

    // Explicit conversion (C-style cast)
    double c = 9.7;
    int d = (int)c;  // explicit conversion
    cout << "Explicit (C-style): " << d << endl;

    // Explicit conversion (static_cast)
    double e = 5.8;
    int f = static_cast<int>(e);
    cout << "Explicit (static_cast): " << f << endl;

    // Division behavior
    cout << "Integer division: " << 10/3 << endl;
    cout << "Float division: " << 10.0/3 << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a=10, b=5;

    // Arithmetic
    cout << "Arithmetic: " << a+b << " " << a-b << " " << a*b << " " << a/b << " " << a%b << endl;

    // Relational
    cout << "Relational: " << (a>b) << " " << (a==b) << " " << (a!=b) << endl;

    // Logical
    cout << "Logical: " << (a>0 && b>0) << " " << (a>0 || b<0) << " " << !(a==b) << endl;

    // Bitwise
    cout << "Bitwise & : " << (a & b) << " | : " << (a | b) << " ^ : " << (a ^ b) << endl;
    cout << "Left shift (a<<1): " << (a<<1) << " Right shift (a>>1): " << (a>>1) << endl;

    // Assignment operators
    int c = 10;
    c += 5;  // c = 15
    c -= 3;  // c = 12
    c *= 2;  // c = 24
    cout << "Assignment result: " << c << endl;

    // Ternary operator
    int x = 5, y = 10;
    int max = (x > y) ? x : y;
    cout << "Max using ternary: " << max << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Pre-increment
    int a = 5;
    cout << "Before pre-increment: a = " << a << endl;
    cout << "++a = " << ++a << endl;  // increments first, returns new value
    cout << "After pre-increment: a = " << a << endl;

    cout << "\n";

    // Post-increment
    int b = 5;
    cout << "Before post-increment: b = " << b << endl;
    cout << "b++ = " << b++ << endl;  // returns current value, then increments
    cout << "After post-increment: b = " << b << endl;

    cout << "\n";

    // In expressions
    int x = 5, y;
    y = ++x + ++x;  // Both pre-increment
    cout << "y = ++x + ++x: x=" << x << " y=" << y << endl;

    x = 5; y = 0;
    y = x++ + x++;  // Both post-increment (behavior may vary)
    cout << "y = x++ + x++: x=" << x << " y=" << y << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Global variable (extern by default)
globalVar = 10;

void testAuto() {
    auto int a = 5;  // auto storage class
    cout << "Auto variable: " << a << endl;
}

void testStatic() {
    static int count = 0;  // static - retains value
    count++;
    cout << "Static count: " << count << endl;
}

void testRegister() {
    register int i;  // register - faster access
    for(i = 0; i < 5; i++)
        cout << "Register: " << i << endl;
}

extern int globalVar;  // declares external variable

int main() {
    cout << "Global variable: " << globalVar << endl;

    cout << "\nCalling testAuto():";
    testAuto();
    testAuto();  // new auto variable each time

    cout << "\nCalling testStatic() thrice:";
    testStatic();
    testStatic();
    testStatic();  // count retains value between calls

    cout << "\nRegister variable:";
    testRegister();

    return 0;
}
